mapper.select:
select count(*) as total, sum(case when c.contract_type = 'trial' then 1 else 0 end) as trialCount, sum(case when c.contract_type = 'paid' then 1 else 0 end) as paidCount, sum(case when c.contract_type is null or c.contract_type = '' then 1 else 0 end) as unsetCount from sys_dept_api_config c
